def write_schema_import_template(output_dir):
    """Write the generated schema import cockpit template."""
    templates_dir = Path(output_dir) / "templates"
    templates_dir.mkdir(parents=True, exist_ok=True)
    (templates_dir / "appgen_schema_import.html").write_text(
        """{% extends "appbuilder/base.html" %}
{% block content %}
<style>
  .agsi-wrap { margin: 18px 0 32px; }
  .agsi-head { display: flex; justify-content: space-between; gap: 16px; align-items: flex-start; margin-bottom: 18px; }
  .agsi-title { margin: 0; font-size: 28px; font-weight: 700; color: #14213d; }
  .agsi-note { color: #52616b; max-width: 860px; line-height: 1.5; }
  .agsi-actions { display: flex; flex-wrap: wrap; gap: 8px; justify-content: flex-end; }
  .agsi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 14px; }
  .agsi-card { border: 1px solid #d9e2ec; background: #fff; padding: 16px; }
  .agsi-card h3 { margin: 0 0 8px; font-size: 17px; color: #14213d; }
  .agsi-muted { color: #64748b; font-size: 12px; }
  .agsi-pill { display: inline-block; border: 1px solid #cbd5e1; padding: 3px 7px; margin: 3px 4px 0 0; font-size: 12px; background: #f8fafc; }
  @media (max-width: 760px) { .agsi-head { display: block; } .agsi-actions { justify-content: flex-start; margin-top: 12px; } }
</style>
<section class="agsi-wrap">
  <div class="agsi-head">
    <div>
      <h1 class="agsi-title">Schema Import</h1>
      <p class="agsi-note">
        Generated import workbench for DBML, SQL DDL, PonyORM scripts, and live
        database introspection, with normalization evidence and reviewable
        generation commands.
      </p>
    </div>
    <div class="agsi-actions">
      <a class="btn btn-default" href="{{ url_for('SchemaImportView.catalog_json') }}">Catalog JSON</a>
      <a class="btn btn-default" href="{{ url_for('SchemaImportView.profile_json') }}">Profile JSON</a>
      <a class="btn btn-default" href="{{ url_for('SchemaImportView.normalization_json') }}">Normalization JSON</a>
      <a class="btn btn-default" href="{{ url_for('SchemaImportView.validation_json') }}">Validation JSON</a>
      <a class="btn btn-default" href="{{ url_for('SchemaImportView.commands_json') }}">Commands JSON</a>
    </div>
  </div>
  <div class="agsi-grid">
    {% for source in sources %}
    <article class="agsi-card">
      <h3>{{ source.label }}</h3>
      <div class="agsi-muted">{{ source.kind }}</div>
      {% for feature in source.normalizes %}
      <span class="agsi-pill">{{ feature }}</span>
      {% endfor %}
    </article>
    {% endfor %}
    <article class="agsi-card">
      <h3>Source Validation</h3>
      <div class="agsi-muted">Pre-generation checks</div>
      <span class="agsi-pill">DBML refs</span>
      <span class="agsi-pill">SQL constraints</span>
      <span class="agsi-pill">PonyORM AST</span>
      <span class="agsi-pill">Database reflection</span>
    </article>
    <article class="agsi-card">
      <h3>Current Source</h3>
      <div class="agsi-muted">{{ profile.source_kind }}</div>
      <span class="agsi-pill">{{ profile.tables }} tables</span>
      <span class="agsi-pill">{{ profile.fields }} fields</span>
      <span class="agsi-pill">{{ profile.relations }} relations</span>
    </article>
  </div>
</section>
{% endblock %}
"""
    )


def write_integrations_template(output_dir):
    """Write the generated integration catalog template."""
    templates_dir = Path(output_dir) / "templates"
    templates_dir.mkdir(parents=True, exist_ok=True)
    (templates_dir / "appgen_integrations.html").write_text(
        """{% extends "appbuilder/base.html" %}
{% block content %}
<style>
  .agi-wrap { margin: 18px 0 32px; }
  .agi-head { display: flex; justify-content: space-between; gap: 16px; align-items: flex-start; margin-bottom: 18px; }
  .agi-title { margin: 0; font-size: 28px; font-weight: 700; color: #14213d; }
  .agi-note { color: #52616b; max-width: 820px; line-height: 1.5; }
  .agi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 14px; }
  .agi-card { border: 1px solid #d9e2ec; background: #fff; padding: 16px; }
  .agi-card h3 { margin: 0 0 8px; font-size: 17px; color: #14213d; }
  .agi-muted { color: #64748b; font-size: 12px; }
  .agi-pill { display: inline-block; border: 1px solid #cbd5e1; padding: 3px 7px; margin: 3px 4px 0 0; font-size: 12px; background: #f8fafc; }
  .agi-ok { color: #176b4d; }
  .agi-missing { color: #9b2c2c; }
  @media (max-width: 760px) { .agi-head { display: block; } }
</style>
<section class="agi-wrap">
  <div class="agi-head">
    <div>
      <h1 class="agi-title">Integrations</h1>
      <p class="agi-note">
        Generated connector registry for REST, webhook, Salesforce, SAP,
        Entando, Invenio, payment gateways, SMS gateways, and transactional email services.
        Secrets stay in environment variables and requests are planned
        explicitly with signed webhooks, idempotency keys, outbox envelopes, and audit
        events before custom connector code sends data.
      </p>
    </div>
    <a class="btn btn-default" href="{{ url_for('IntegrationView.catalog_json') }}">Catalog JSON</a>
  </div>
  <div class="agi-grid">
    {% for item in integrations %}
    <article class="agi-card">
      <h3>{{ item.label }}</h3>
      <div class="agi-muted">{{ item.kind }} - {{ item.description }}</div>
      <p class="{{ 'agi-ok' if item.configured else 'agi-missing' }}">
        {{ "Configured" if item.configured else "Missing configuration" }}
      </p>
      {% for key in item.env %}
      <span class="agi-pill">{{ key }}</span>
      {% endfor %}
    </article>
    {% endfor %}
  </div>
</section>
{% endblock %}
"""
    )


