def database_provider_catalog():
    """Return generated database provider targets."""
    return tuple(dict(spec, provider=name) for name, spec in DATABASE_PROVIDERS.items())


def database_addon_catalog():
    """Return generated database-adjacent operational add-ons."""
    return tuple(dict(spec, addon=name) for name, spec in DATABASE_ADDONS.items())


def relational_provider_catalog():
    """Return generated relational database providers."""
    return tuple(item for item in database_provider_catalog() if item["kind"] == "relational")


def nosql_provider_catalog():
    """Return generated NoSQL database providers."""
    return tuple(item for item in database_provider_catalog() if item["kind"] != "relational")


def provider_plan(provider, environ=None):
    """Return readiness metadata for a database provider."""
    env = {{}} if environ is None else environ
    spec = DATABASE_PROVIDERS[provider]
    missing = tuple(key for key in spec["env"] if not env.get(key))
    return dict(spec, provider=provider, configured=not missing, missing=missing, tables=DATABASE_TABLES)


def nosql_provider_plan(provider, environ=None):
    """Return readiness metadata for a generated NoSQL provider."""
    if provider not in {{item["provider"] for item in nosql_provider_catalog()}}:
        raise KeyError(f"Unknown NoSQL database provider: {{provider}}")
    return provider_plan(provider, environ)


def addon_plan(addon, environ=None):
    """Return readiness metadata for a database operations add-on."""
    env = {{}} if environ is None else environ
    spec = DATABASE_ADDONS[addon]
    missing = tuple(key for key in spec["env"] if not env.get(key))
    return dict(spec, addon=addon, configured=not missing, missing=missing)


def compose_service_plan(provider="postgresql"):
    """Return Docker Compose service descriptors for database providers."""
    if provider == "postgresql":
        return {{
            "service": "postgres",
            "image": "postgres:16",
            "ports": ("5432:5432",),
            "volumes": ("postgres-data:/var/lib/postgresql/data",),
            "env": DATABASE_PROVIDERS["postgresql"]["env"],
        }}
    if provider == "mysql":
        return {{
            "service": "mysql",
            "image": "mysql:8",
            "ports": ("3306:3306",),
            "volumes": ("mysql-data:/var/lib/mysql",),
            "env": DATABASE_PROVIDERS["mysql"]["env"],
        }}
    if provider == "sqlite":
        return {{
            "service": "sqlite",
            "image": None,
            "ports": tuple(),
            "volumes": ("./data:/app/data",),
            "env": DATABASE_PROVIDERS["sqlite"]["env"],
        }}
    if provider == "mongodb":
        return {{
            "service": "mongodb",
            "image": "mongo:7",
            "ports": ("27017:27017",),
            "volumes": ("mongodb-data:/data/db",),
            "env": DATABASE_PROVIDERS["mongodb"]["env"],
        }}
    if provider == "dynamodb":
        return {{
            "service": "dynamodb-local",
            "image": "amazon/dynamodb-local:latest",
            "ports": ("8000:8000",),
            "volumes": ("dynamodb-data:/home/dynamodblocal/data",),
            "env": DATABASE_PROVIDERS["dynamodb"]["env"],
        }}
    if provider == "cassandra":
        return {{
            "service": "cassandra",
            "image": "cassandra:5",
            "ports": ("9042:9042",),
            "volumes": ("cassandra-data:/var/lib/cassandra",),
            "env": DATABASE_PROVIDERS["cassandra"]["env"],
        }}
    if provider == "redis":
        return {{
            "service": "redis",
            "image": "redis:7-alpine",
            "ports": ("6379:6379",),
            "volumes": ("redis-data:/data",),
            "env": DATABASE_PROVIDERS["redis"]["env"],
        }}
    raise KeyError(f"Unknown database provider: {{provider}}")


def kubernetes_statefulset_plan(provider="postgresql"):
    """Return Kubernetes stateful workload descriptors for database providers."""
    service = compose_service_plan(provider)
    return {{
        "kind": "StatefulSet" if provider in {{"postgresql", "mysql", "mongodb", "cassandra", "redis"}} else "PersistentVolumeClaim",
        "provider": provider,
        "service": service["service"],
        "ports": service["ports"],
        "volumes": service["volumes"],
    }}


def migration_target_matrix():
    """Return generated migration targets for supported database engines."""
    return tuple(
        {{
            "provider": provider,
            "kind": spec["kind"],
            "sqlalchemy_prefix": spec.get("sqlalchemy_prefix"),
            "tables": DATABASE_TABLES,
            "alembic": spec["kind"] == "relational",
        }}
        for provider, spec in DATABASE_PROVIDERS.items()
    )


def schema_inventory():
    """Return generated table, key, and relationship inventory for migration planning."""
    return tuple(dict(spec, table=table_name) for table_name, spec in SCHEMA_INVENTORY.items())


def migration_source_profile(source=None):
    """Return normalized legacy-source metadata for import/introspection reviews."""
    source = dict(source or {{}})
    provider = str(source.get("provider") or source.get("engine") or "unknown").lower()
    tables = tuple(source.get("tables") or DATABASE_TABLES)
    row_counts = dict(source.get("row_counts") or {{}})
    missing_tables = tuple(table for table in DATABASE_TABLES if table not in tables)
    extra_tables = tuple(table for table in tables if table not in DATABASE_TABLES)
    return {{
        "provider": provider,
        "tables": tables,
        "row_counts": row_counts,
        "missing_tables": missing_tables,
        "extra_tables": extra_tables,
        "known_provider": provider in DATABASE_PROVIDERS,
    }}


def migration_risk_assessment(source=None):
    """Return a deterministic risk assessment for migrating legacy data."""
    profile = migration_source_profile(source)
    risks = []
    if profile["missing_tables"]:
        risks.append({{"level": "high", "kind": "missing_tables", "tables": profile["missing_tables"]}})
    if profile["extra_tables"]:
        risks.append({{"level": "medium", "kind": "extra_tables", "tables": profile["extra_tables"]}})
    if not profile["known_provider"] and profile["provider"] != "unknown":
        risks.append({{"level": "medium", "kind": "unknown_provider", "provider": profile["provider"]}})
    for table_name, spec in SCHEMA_INVENTORY.items():
        required = tuple(field for field in spec["required_fields"] if field not in spec["primary_keys"])
        references = tuple(spec["references"])
        if required:
            risks.append({{"level": "medium", "kind": "required_fields", "table": table_name, "fields": required}})
        if references:
            risks.append({{"level": "low", "kind": "foreign_keys", "table": table_name, "references": references}})
    high_count = sum(1 for item in risks if item["level"] == "high")
    medium_count = sum(1 for item in risks if item["level"] == "medium")
    return {{
        "format": "appgen.database-migration-risk.v1",
        "provider": profile["provider"],
        "risk_level": "high" if high_count else ("medium" if medium_count else "low"),
        "risks": tuple(risks),
        "table_count": len(DATABASE_TABLES),
        "estimated_rows": sum(int(value or 0) for value in profile["row_counts"].values()),
    }}


def migration_cutover_plan(source=None, target_provider="postgresql"):
    """Return reviewable steps for migrating a legacy database into the generated app."""
    assessment = migration_risk_assessment(source)
    target = provider_plan(target_provider, {{}})
    steps = [
        {{"name": "inventory", "action": "export_schema_inventory", "tables": DATABASE_TABLES}},
        {{"name": "profile", "action": "profile_legacy_source", "provider": assessment["provider"]}},
        {{"name": "dry_run", "action": "run_data_exchange_validation", "risk_level": assessment["risk_level"]}},
        {{"name": "backup", "action": "create_source_and_target_backups", "required": True}},
        {{"name": "load", "action": "apply_reviewed_batches", "target_provider": target_provider}},
        {{"name": "verify", "action": "compare_counts_and_foreign_keys", "tables": DATABASE_TABLES}},
    ]
    if assessment["risk_level"] in {{"high", "medium"}}:
        steps.insert(3, {{"name": "remediate", "action": "resolve_required_field_and_relationship_risks", "required": True}})
    return {{
        "format": "appgen.database-cutover-plan.v1",
        "target_provider": target_provider,
        "target_kind": target["kind"],
        "risk_level": assessment["risk_level"],
        "requires_review": True,
        "steps": tuple(steps),
        "rollback": ("restore_target_backup", "replay_previous_app_release"),
    }}


def document_projection(table_name):
    """Return a generated NoSQL document projection for one table."""
    if table_name not in DATABASE_TABLES:
        raise KeyError(f"Unknown table: {{table_name}}")
    return {{
        "table": table_name,
        "collection": table_name.lower(),
        "partition_key": "id",
        "document_shape": "manifest-row",
        "providers": tuple(item["provider"] for item in nosql_provider_catalog()),
    }}


def document_projection_matrix():
    """Return generated table-to-NoSQL projection contracts."""
    return tuple(document_projection(table_name) for table_name in DATABASE_TABLES)


