    @expose("/catalog.json")
    def catalog_json(self):
        return jsonify(list(text_quality_catalog()))

    @expose("/<table_name>/<field_name>.json")
    def field_json(self, table_name, field_name):
        return jsonify(text_field(table_name, field_name))


